/// One `cargo cicd <noun> <verb>` command row.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct CargoCicdCommand {
    pub noun: &'static str,
    pub verb: &'static str,
    pub doc: &'static str,
    /// Path (relative to `~/cargo-cicd`) of the source file this row was
    /// audited against, e.g. `"src/nouns/git.rs"`. Empty string only for
    /// the deprecated `doctor`/`""` compatibility row.
    pub source_file: &'static str,
    /// Number of real CLI-facing arguments the underlying `cmd_*` function
    /// takes, source-verified against `~/cargo-cicd`.
    pub arg_count: u8,
    /// `"name:Type;name:Type;..."` for commands with `arg_count > 0`, else
    /// `""`. Source-verified, not invented.
    pub args: &'static str,
}

