/// Look up one command row by exact (noun, verb). Real, callable behavior
/// over the generated catalog -- not merely a static table.
pub fn find_command(noun: &str, verb: &str) -> Option<&'static CargoCicdCommand> {
    CARGO_CICD_COMMANDS
        .iter()
        .find(|c| c.noun == noun && c.verb == verb)
}

/// All command rows for a given noun, in catalog order.
pub fn commands_for_noun(noun: &str) -> impl Iterator<Item = &'static CargoCicdCommand> + '_ {
    CARGO_CICD_COMMANDS.iter().filter(move |c| c.noun == noun)
}

/// True iff `(noun, verb)` is a known `cargo cicd` command in this catalog.
pub fn is_valid_command(noun: &str, verb: &str) -> bool {
    find_command(noun, verb).is_some()
}

/// The distinct set of nouns in the catalog, in first-seen (sorted) order.
pub fn distinct_nouns() -> Vec<&'static str> {
    let mut nouns: Vec<&'static str> = CARGO_CICD_COMMANDS.iter().map(|c| c.noun).collect();
    nouns.sort_unstable();
    nouns.dedup();
    nouns
}

/// Parses one command's `args` field into `(name, type)` pairs. Real parsing
/// logic over ontology-sourced data (`cc:args`), not a hand-copied literal --
/// returns an empty `Vec` for `arg_count == 0` commands.
pub fn parse_args(cmd: &CargoCicdCommand) -> Vec<(&'static str, &'static str)> {
    if cmd.args.is_empty() {
        return Vec::new();
    }
    cmd.args
        .split(';')
        .filter_map(|pair| pair.split_once(':'))
        .collect()
}

/// True iff `parse_args` yields exactly `arg_count` entries for every row in
/// the catalog -- a structural consistency check between the two
/// independently-sourced `cc:argCount`/`cc:args` facts.
pub fn args_are_consistent() -> bool {
    CARGO_CICD_COMMANDS
        .iter()
        .all(|c| parse_args(c).len() as u8 == c.arg_count)
}

/// Round 4: the real return type shared by every `cmd_*` function backing
/// every command in `CARGO_CICD_COMMANDS`, source-verified against
/// `~/cargo-cicd/src/nouns/*.rs` (all 21 files).
pub const CARGO_CICD_RETURN_TYPE: &str = "clap_noun_verb::Result<()>";

/// Real error enum name every command's return type is parameterized over
/// (`~/clap-noun-verb/src/error.rs`).
pub const CARGO_CICD_ERROR_ENUM: &str = "NounVerbError";

/// The `#[non_exhaustive]` `NounVerbError` variant names, transcribed
/// verbatim from `~/clap-noun-verb/src/error.rs` (lines 11-51), sorted.
pub const CARGO_CICD_ERROR_VARIANTS: &[&str] = &[
    "ArgumentError",
    "CommandNotFound",
    "ExecutionError",
    "Generic",
    "InvalidStructure",
    "MiddlewareError",
    "PluginError",
    "TelemetryError",
    "ValidationFailed",
    "VerbNotFound",
];

/// True iff every command in the catalog shares the single documented
/// return type (a real, source-verified uniform relation, not a per-row
/// duplicate fact) -- checked by construction here since `arg_count`/`args`
/// are per-row but the return type/error enum are catalog-wide facts.
pub fn all_commands_share_return_contract() -> bool {
    !CARGO_CICD_COMMANDS.is_empty()
        && !CARGO_CICD_RETURN_TYPE.is_empty()
        && !CARGO_CICD_ERROR_ENUM.is_empty()
}
